"use client"
import { useEffect, useState } from 'react';
import { useParams } from "next/navigation";
import axios from 'axios';
import { GoSignOut } from "react-icons/go";
import { CgProfile } from "react-icons/cg";
import { signOut } from "next-auth/react";
import { toast } from "react-toastify"; // Importing Toast for notifications
import { useRouter } from 'next/navigation';

function UserProfile() {
    const router=useRouter()
  const { id } = useParams();  // Extract the `id` from the URL using useParams
  const [userDetails, setUserDetails] = useState(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);

  const [showUpdateModal, setShowUpdateModal] = useState(false);
  const [formData, setFormData] = useState({
    username: '',
    email: '',
    phone: '',
    instagram: '',
    youtube: '',
    facebook: '',
    password: ''
  });

  // Fetch user details
  useEffect(() => {
    const fetchUserDetails = async () => {
      try {
        const res = await axios.get(`http://localhost:5000/api/user/${id}`);
        setUserDetails(res.data);
        setLoading(false);
      } catch (err) {
        setError("Failed to load user details");
        setLoading(false);
      }
    };

    if (id) {
      fetchUserDetails();
    }
  }, [id]);

  // Pre-fill form data when modal opens
  const handleOpenUpdateModal = () => {
    if (userDetails) {
      setFormData({
        username: userDetails.username || '',
        email: userDetails.email || '',
        phone: userDetails.phone || '',
        instagram: userDetails.instagram || '',
        youtube: userDetails.youtube || '',
        facebook: userDetails.facebook || '',
        password: ''  // Password remains optional
      });
      setShowUpdateModal(true);
    }
  };

  // Handle form changes
  const handleChange = (e) => {
    const { name, value } = e.target;
    setFormData(prev => ({ ...prev, [name]: value }));
  };

  // Handle profile update submission
  const handleUpdateSubmit = async (e) => {
    e.preventDefault();
    try {
      // If password is empty, we don't update the password field
      const updateData = formData.password ? formData : { ...formData, password: undefined };
      await axios.put(`http://localhost:5000/api/update/${id}`, updateData);
      toast.success("Profile updated successfully");
      setShowUpdateModal(false);
      // Refresh user details after update
      setUserDetails(prev => ({ ...prev, ...formData }));
    } catch (err) {
      toast.error("Failed to update profile");
    }
  };

  // Handle sign out
  const handleSignOut = async () => {
    await signOut({ redirect: false });
    toast.success("Signed out successfully");
    router.push("/homepage")
  };

  if (loading) return <div>Loading...</div>;
  if (error) return <div>{error}</div>;

  return (
    <div className="flex min-h-screen items-center justify-center bg-gradient-to-br from-indigo-50 to-gray-100 p-4">
      {/* Profile Card */}
      <div className="w-full max-w-md rounded-2xl bg-white p-6 shadow-xl transition-all duration-300 hover:shadow-2xl sm:max-w-lg sm:p-8">
        <div className="mb-6 flex justify-center">
          <CgProfile className="text-6xl text-indigo-600 transition-transform duration-300 hover:scale-110" />
        </div>
        <h1 className="mb-6 text-center text-2xl font-bold text-gray-800 sm:text-3xl">
          {userDetails.username}
        </h1>

        {/* Profile Details */}
        <div className="space-y-3 text-gray-600">
          {[
            { label: "Email", value: userDetails.email },
            { label: "Phone", value: userDetails.phone },
            { label: "Role", value: userDetails.role },
            {
              label: "Instagram",
              value: userDetails.instagram,
              isLink: true,
            },
            { label: "YouTube", value: userDetails.youtube, isLink: true },
            { label: "Facebook", value: userDetails.facebook, isLink: true },
            {
              label: "Created",
              value: new Date(userDetails.createdAt).toLocaleDateString(),
            },
            {
              label: "Updated",
              value: userDetails.updatedAt
                ? new Date(userDetails.updatedAt).toLocaleDateString()
                : null,
            },
          ].map(
            ({ label, value, isLink }) =>
              value && (
                <div key={label} className="flex items-center gap-4">
                  <span className="w-20 font-semibold text-gray-700 sm:w-24">
                    {label}:
                  </span>
                  {isLink ? (
                    <a
                      href={value}
                      target="_blank"
                      rel="noopener noreferrer"
                      className="text-indigo-600 hover:underline"
                    >
                      {value}
                    </a>
                  ) : (
                    <span>{value}</span>
                  )}
                </div>
              )
          )}
        </div>

        {/* Action Buttons */}
        <div className="mt-8 flex flex-col gap-4 sm:flex-row">
          <button
            onClick={handleOpenUpdateModal}
            className="flex-1 rounded-lg bg-indigo-600 px-4 py-2 font-semibold text-white transition-all duration-300 hover:bg-indigo-700 hover:shadow-md"
          >
            Update Profile
          </button>
          <button
            onClick={handleSignOut}
            className="flex flex-1 items-center justify-center gap-2 rounded-lg bg-red-600 px-4 py-2 font-semibold text-white transition-all duration-300 hover:bg-red-700 hover:shadow-md"
          >
            <GoSignOut className="text-lg" />
            Sign Out
          </button>
        </div>
      </div>

      {/* Update Modal */}
      {showUpdateModal && (
        <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/50 backdrop-blur-sm transition-opacity duration-300">
          <div className="relative w-full max-w-md rounded-2xl bg-white p-6 shadow-2xl transition-transform duration-300 sm:p-8">
            <button
              onClick={() => setShowUpdateModal(false)}
              className="absolute right-4 top-4 text-2xl text-gray-500 hover:text-gray-800"
              aria-label="Close modal"
            >
              ×
            </button>
            <h2 className="mb-6 text-center text-xl font-bold text-gray-800 sm:text-2xl">
              Update Profile
            </h2>
            <form onSubmit={handleUpdateSubmit} className="space-y-4">
              {[
                { name: "username", type: "text", placeholder: "Username" },
                { name: "email", type: "email", placeholder: "Email" },
                { name: "phone", type: "tel", placeholder: "Phone Number" },
                { name: "instagram", type: "url", placeholder: "Instagram Link" },
                { name: "youtube", type: "url", placeholder: "YouTube Link" },
                { name: "facebook", type: "url", placeholder: "Facebook Link" },
                {
                  name: "password",
                  type: "password",
                  placeholder: "New Password (Optional)",
                },
              ].map((field) => (
                <input
                  key={field.name}
                  type={field.type}
                  name={field.name}
                  value={formData[field.name]}
                  onChange={handleChange}
                  placeholder={field.placeholder}
                  className="w-full rounded-lg border border-gray-300 px-4 py-2 focus:border-indigo-500 focus:outline-none focus:ring-2 focus:ring-indigo-200"
                  aria-label={field.placeholder}
                />
              ))}
              <div className="flex flex-col gap-4 sm:flex-row">
                <button
                  type="submit"
                  className="flex-1 rounded-lg bg-indigo-600 px-4 py-2 font-semibold text-white hover:bg-indigo-700"
                >
                  Save
                </button>
                <button
                  type="button"
                  onClick={() => setShowUpdateModal(false)}
                  className="flex-1 rounded-lg bg-gray-400 px-4 py-2 font-semibold text-white hover:bg-gray-500"
                >
                  Cancel
                </button>
              </div>
            </form>
          </div>
        </div>
      )}
    </div>
  );
}

export default UserProfile;
